// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Helper function to get weather emoji based on condition
  const getWeatherEmoji = (condition: string): string => {
    const normalized = condition.toLowerCase();
    if (normalized.includes('sunny') || normalized.includes('clear')) return '☀️';
    if (normalized.includes('cloudy') || normalized.includes('cloud')) return '☁️';
    if (normalized.includes('rainy') || normalized.includes('rain')) return '🌧️';
    if (normalized.includes('snow') || normalized.includes('snowy')) return '❄️';
    if (normalized.includes('thunder') || normalized.includes('storm')) return '⛈️';
    if (normalized.includes('windy') || normalized.includes('wind')) return '💨';
    if (normalized.includes('fog') || normalized.includes('mist')) return '🌫️';
    return '🌤️';
  };

  const weatherEmoji = getWeatherEmoji(props.condition);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)" align="stretch">
        {/* Main Weather Card */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
          <Stack gap="var(--ggui-spacing-6)" align="center" justify="center">
            {/* City Name */}
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              {props.city}
            </Heading>

            {/* Weather Condition with Icon/Emoji */}
            <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
              <Text style={{ fontSize: '64px' }}>{weatherEmoji}</Text>
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {props.condition}
              </Text>
            </Stack>

            {/* Current Temperature - Large and Prominent */}
            <div style={{
              fontSize: '72px',
              fontWeight: 'var(--ggui-font-weight-bold, 700)',
              color: 'var(--ggui-color-primary-600, #0284c7)',
              lineHeight: '1',
            }}>
              {Math.round(props.temperature)}°{props.unit}
            </div>

            {/* Divider */}
            <Divider orientation="horizontal" margin="var(--ggui-spacing-4)" color="var(--ggui-color-outlineVariant, #e4e4e7)" />

            {/* Humidity and Wind Speed */}
            <Stack direction="horizontal" gap="var(--ggui-spacing-8)" align="center" justify="center">
              <Box paddingX="var(--ggui-spacing-4)" paddingY="var(--ggui-spacing-2)">
                <Stack gap="var(--ggui-spacing-1)" align="center" justify="center">
                  <Icon name="droplets" size={24} color="var(--ggui-color-primary-500, #0ea5e9)" />
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Humidity
                  </Text>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    {props.humidity}%
                </Stack>
              </Box>

              <Divider orientation="vertical" margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant, #e4e4e7)" />

              <Box paddingX="var(--ggui-spacing-4)" paddingY="var(--ggui-spacing-2)">
                <Stack gap="var(--ggui-spacing-1)" align="center" justify="center">
                  <Icon name="wind" size={24} color="var(--ggui-color-primary-500, #0ea5e9)" />
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Wind Speed
                  </Text>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    {props.windSpeed} km/h
                </Stack>
              </Box>
            </Stack>
          </Stack>
        </Card>

        {/* 5-Day Forecast */}
        <Stack gap="var(--ggui-spacing-4)">
          <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
            5-Day Forecast
          </Heading>

           <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-2)' }}>
             <Stack direction="horizontal" gap="var(--ggui-spacing-4)" style={{ minWidth: 'min-content' }}>
               {props.forecast.map((day, index) => (
                 <Card
                   key={index}
                   shadow="sm"
                   padding="var(--ggui-spacing-4)"
                   radius="md"
                   style={{
                     flex: '0 0 auto',
                     minWidth: 'var(--ggui-spacing-30)',
                     textAlign: 'center',
                   }}
              >
                <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                  {/* Day Name */}
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    {day.day || `Day ${index + 1}`}
                  </Text>

                  {/* Weather Icon/Emoji */}
                  <Text style={{ fontSize: '32px' }}>
                    {day.icon || getWeatherEmoji('')}
                  </Text>
                  {/* High/Low Temps */}
                  <Box>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                    {day.high !== undefined ? Math.round(day.high) : '--'}°{props.unit}
                  </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {day.low !== undefined ? Math.round(day.low) : '--'}°{props.unit}
                    </Text>
                  </Box>
                </Stack>
              </Card>
               ))}
             </Stack>
           </Box>
        </Stack>
      </Stack>
    </Container>
  );
}

