// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };



// Helper: Get priority color variant
function getPriorityVariant(priority?: string): 'default' | 'primary' | 'success' | 'warning' | 'error' | 'info' {
  switch (priority) {
    case 'high': return 'error';
    case 'medium': return 'warning';
    case 'low': return 'success';
    default: return 'default';
  }
}

// Helper: Get priority display text
function getPriorityLabel(priority?: string): string {
  return priority ? priority.charAt(0).toUpperCase() + priority.slice(1) : 'No priority';
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // State management
  const [localTasks, setLocalTasks] = useState(props.tasks);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTaskTitle, setEditingTaskTitle] = useState('');
  const [addingToColumnId, setAddingToColumnId] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // Sync with props.tasks when they change
  useEffect(() => {
    setLocalTasks(props.tasks);
  }, [props.tasks]);

  // Apply real-time updates from stream
  useEffect(() => {
    if (taskChanged.latest?.task) {
      const changedTask = taskChanged.latest.task;
      const action = taskChanged.latest.action;

      if (action === 'delete' && changedTask.id) {
        setLocalTasks((prev) => prev.filter((t) => t.id !== changedTask.id));
      } else if (action === 'create' || action === 'move' || action === 'edit') {
        setLocalTasks((prev) => {
          const existing = prev.findIndex((t) => t.id === changedTask.id);
          if (existing >= 0) {
            return [...prev.slice(0, existing), changedTask, ...prev.slice(existing + 1)];
          }
          return [...prev, changedTask];
        });
      }
    }
  }, [taskChanged.latest]);

  // Computed: Total and completed tasks
  const completedCount = useMemo(() => {
    const doneColumnId = props.columns.find((c) => c.name?.toLowerCase().includes('done'))?.id;
    return doneColumnId ? localTasks.filter((t) => t.column === doneColumnId).length : 0;
  }, [localTasks, props.columns]);

  const totalCount = localTasks.length;

  // Handlers
  const handleMoveTask = useCallback(
    (taskId: string, newColumnId: string) => {
      setLocalTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, column: newColumnId } : t))
      );
      taskUpdate({ action: 'move', taskId, data: { column: newColumnId } });
    },
    [taskUpdate]
  );

  const handleEditTask = (taskId: string, currentTitle: string) => {
    setEditingTaskId(taskId);
    setEditingTaskTitle(currentTitle);
  };

  const handleSaveEdit = useCallback(
    (taskId: string) => {
      if (editingTaskTitle.trim()) {
        setLocalTasks((prev) =>
          prev.map((t) => (t.id === taskId ? { ...t, title: editingTaskTitle } : t))
        );
        taskUpdate({ action: 'edit', taskId, data: { column: localTasks.find((t) => t.id === taskId)?.column || 'todo' } });
      }
      setEditingTaskId(null);
      setEditingTaskTitle('');
    },
    [editingTaskTitle, localTasks, taskUpdate]
  );

  const handleCreateTask = useCallback(
    (columnId: string) => {
      if (newTaskTitle.trim()) {
        const newTask = {
          id: `task-${Date.now()}`,
          title: newTaskTitle,
          priority: newTaskPriority,
          column: columnId,
        };
        setLocalTasks((prev) => [...prev, newTask]);
        taskUpdate({ action: 'create', taskId: newTask.id, data: { column: columnId } });
      }
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddingToColumnId(null);
    },
    [newTaskTitle, newTaskPriority, taskUpdate]
  );

  // Get tasks for a specific column
  const getTasksForColumn = (columnId: string) => {
    return localTasks.filter((t) => t.column === columnId);
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Card shadow="sm" padding="var(--ggui-spacing-4)" border={true}>
          <Stack direction="horizontal" justify="between" align="center">
            <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="center">
              <Heading level={3}>Task Board</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {completedCount} of {totalCount} completed
              </Text>
            </Stack>
            <Progress value={totalCount > 0 ? (completedCount / totalCount) * 100 : 0} variant="success" size="md" />
          </Stack>
        </Card>

        {/* Columns Layout */}
        {/* Columns Layout */}
        <Row gap="var(--ggui-spacing-4)">
          {props.columns.map((column) => {
            const columnTasks = getTasksForColumn(column.id || '');
            return (
              <Card
                key={column.id}
                shadow="sm"
                padding="var(--ggui-spacing-4)"
                border={true}
                style={{ flex: 1, minWidth: '300px', maxHeight: '70vh', overflowY: 'auto' }}
              >
                <Stack gap="var(--ggui-spacing-4)">
                  {/* Column Header */}
                  <Stack direction="horizontal" justify="between" align="center">
                    <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                      <Heading level={4}>{column.name}</Heading>
                      <Badge variant="secondary" size="sm">
                        {columnTasks.length}
                      </Badge>
                    </Stack>
                  </Stack>

                  {/* Task Cards */}
                  <Stack gap="var(--ggui-spacing-2)">
                    {columnTasks.map((task) => (
                      <Card
                        key={task.id}
                        shadow="sm"
                        padding="var(--ggui-spacing-3)"
                        border={true}
                        style={{
                          backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                        }}
                      >
                        <Stack gap="var(--ggui-spacing-2)">
                          {/* Task Title (Editable) */}
                          {editingTaskId === task.id ? (
                            <Stack direction="horizontal" gap="var(--ggui-spacing-1)" align="center">
                              <Input
                                label="Edit task"
                                value={editingTaskTitle}
                                onChange={setEditingTaskTitle}
