import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Derived values
  const product = props.product || {};
  const isOutOfStock = !product.stock || product.stock <= 0;
  const isLowStock = product.stock && product.stock > 0 && product.stock <= 5;
  const stockStatus = isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock';
  const stockStatusVariant: 'error' | 'warning' | 'success' = isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success';
  const stockColor = isOutOfStock ? 'var(--ggui-color-error-600)' : isLowStock ? 'var(--ggui-color-warning-600)' : 'var(--ggui-color-success-600)';
  const maxQuantity = product.stock || 1;

  // Handlers
  const handleQuantityChange = useCallback((value: number) => {
    const newQty = Math.max(1, Math.min(value, maxQuantity));
    setQuantity(newQty);
  }, [maxQuantity]);

  const handleAddToCart = useCallback(() => {
    if (product.id && quantity > 0) {
      addToCart({ productId: product.id, quantity });
    }
  }, [product.id, quantity, addToCart]);

  // Render star rating
  const renderStars = (rating: number | undefined) => {
    if (!rating) return null;
    const stars = [];
    for (let i = 1; i <= 5; i++) {
      stars.push(
        <Icon
          key={i}
          name={i <= Math.round(rating) ? 'star' : 'star'}
          size={16}
          color={i <= Math.round(rating) ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
        />
      );
    }
    return stars;
  };

  // Format price with currency
  const formatPrice = (price: number | undefined, currency: string | undefined) => {
    if (price === undefined) return 'N/A';
    const currencySymbol = currency || '$';
    return `${currencySymbol}${price.toFixed(2)}`;
  };

  // Prepare tab items
  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Text variant="body" color="var(--ggui-color-onSurface)">{product.description || 'No description available.'}</Text>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Stack gap="var(--ggui-spacing-4)">{Array.isArray(product.specifications) && product.specifications.length > 0 ? (
          <Table
            columns={[
              { key: 'key', header: 'Property' },
              { key: 'value', header: 'Value' },
            ]}
            data={product.specifications as any}
            compact
          />
        ) : (
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">No specifications available.</Text>
        )}</Stack>
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Stack gap="var(--ggui-spacing-4)">{Array.isArray(product.reviews) && product.reviews.length > 0 ? (
          product.reviews.map((review: any, idx) => (
            <Card key={idx} padding="var(--ggui-spacing-4)" shadow="sm">
              <Stack gap="var(--ggui-spacing-2)">
                <Row align="center" gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurface)">{review.author || 'Anonymous'}</Text>
                  <Row gap="var(--ggui-spacing-1)">{renderStars(review.rating)}</Row>
                </Row>
                <Text variant="body" color="var(--ggui-color-onSurface)">{review.text || review.content || ''}</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{review.date ? new Date(review.date).toLocaleDateString() : 'No date'}</Text>
              </Stack>
            </Card>
          ))
        ) : (
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">No reviews yet.</Text>
        )}</Stack>
      ),
    },
  ];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Top Section: Image, Title, Price, Rating, Stock Status */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-8)" align="start" wrap>
          {/* Product Image Placeholder */}
          <Box
            background="var(--ggui-color-primary-100)"
            borderRadius="var(--ggui-shape-radius-lg)"
            padding="var(--ggui-spacing-12)"
            style={{ minWidth: '300px', maxWidth: '400px', width: '100%', aspectRatio: '1', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Stack align="center" gap="var(--ggui-spacing-4)">
              <Icon name="image" size={48} color="var(--ggui-color-primary-600)" />
              <Text variant="body" color="var(--ggui-color-primary-700)" align="center">
                {product.name || 'Product Image'}
              </Text>
            </Stack>
          </Box>

          {/* Product Details */}
          <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, minWidth: '300px' }}>
            <Heading level={1} color="var(--ggui-color-onSurface)">{product.name || 'Product Name'}</Heading>

            {/* Price */}
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-primary-600)">{formatPrice(product.price, product.currency)}</Text>

            {/* Rating */}
            <Row align="center" gap="var(--ggui-spacing-2)">
              <Row gap="var(--ggui-spacing-1)">{renderStars(product.rating)}</Row>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">({product.reviewCount || 0} reviews)</Text>
            </Row>

            {/* Stock Status Badge */}
            <Badge variant={stockStatusVariant} size="md">
              {stockStatus}
            </Badge>
          </Stack>
        </Stack>

        {/* Middle Section: Tabs */}
        <Tabs
          items={tabItems}
          activeKey={activeTab}
          onChange={setActiveTab}
          variant="line"
          size="md"
        />

        {/* Bottom Section: Quantity Selector and Add to Cart */}
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            <Text variant="label" color="var(--ggui-color-onSurface)">Quantity</Text>
            <Row align="center" gap="var(--ggui-spacing-2)">
              <Button
                variant="outline"
                size="sm"
                onClick={() => handleQuantityChange(quantity - 1)}
                disabled={quantity <= 1}
              >
                −
              </Button>
              <Text variant="body" style={{ minWidth: '40px', textAlign: 'center' }} color="var(--ggui-color-onSurface)">{quantity}</Text>
              <Button
                variant="outline"
                size="sm"
                onClick={() => handleQuantityChange(quantity + 1)}
                disabled={quantity >= maxQuantity}
              >
                +
              </Button>
            </Row>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              {maxQuantity > 0 ? `${maxQuantity} in stock` : 'Out of stock'}
            </Text>
          </Stack>

          <Divider margin="var(--ggui-spacing-4)" />

          <Button
            variant="primary"
            size="lg"
            fullWidth
            disabled={isOutOfStock}
            onClick={handleAddToCart}
          >
            {isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
          </Button>
        </Card>
      </Stack>
    </Container>
  );
}
}

