  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State
  const [messageText, setMessageText] = useState<string>('');
  const [allMessages, setAllMessages] = useState(props.messages || []);
  const [typingUser, setTypingUser] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  // Append new messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest!]);
      scrollToBottom();
    }
  }, [message.latest, scrollToBottom]);

  // Handle typing indicator
  useEffect(() => {
    if (typing.latest) {
      if (typing.latest.active) {
        setTypingUser(typing.latest.sender || 'Someone');
      } else {
        setTypingUser(null);
      }
    }
  }, [typing.latest]);

  // Handle message send on Enter key or button click
  const handleSendMessage = useCallback(() => {
    if (messageText.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: messageText.trim(), timestamp });
      setMessageText('');
      scrollToBottom();
    }
  }, [messageText, sendMessage, scrollToBottom]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage();
      }
    },
    [handleSendMessage]
  );

  // Format timestamp for display
  const formatTime = (timestamp?: string): string => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return timestamp;
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
        <Stack gap="var(--ggui-spacing-4)" direction="vertical">
          {/* Header with title, participant count, and typing indicator */}
          <Box paddingBottom="var(--ggui-spacing-4)" borderRadius="var(--ggui-shape-radius-md, 8px)">
            <Stack direction="horizontal" justify="between" align="center">
              <Stack direction="vertical" gap="var(--ggui-spacing-2)">
                <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                  {props.title}
                </Heading>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}
                </Text>
              </Stack>
              {typingUser && (
                <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                  <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />
                  <Text variant="caption" color="var(--ggui-color-primary-600, #0284c7)">
                    {typingUser} is typing
                  </Text>
                </Stack>
              )}
            </Stack>
          </Box>

          <Divider margin="var(--ggui-spacing-2)" />

          {/* Messages scrollable area */}
          <Box
            style={{
              display: 'flex',
              flexDirection: 'column',
              gap: 'var(--ggui-spacing-4)',
              overflowY: 'auto',
              maxHeight: '400px',
              paddingRight: 'var(--ggui-spacing-2)',
            }}
          >
            {allMessages.map((msg, idx) => {
              const isCurrentUser = msg.sender === props.currentUser;
              return (
                <Stack
                  key={idx}
                  direction="horizontal"
                  justify={isCurrentUser ? 'end' : 'start'}
                  align="end"
                  gap="var(--ggui-spacing-2)"
                >
                  {!isCurrentUser && (
                    <Avatar name={msg.sender || 'Unknown'} size="sm" shape="circle" />
                  )}
                  <Box
                    background={
                      isCurrentUser
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                    }
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                    padding="var(--ggui-spacing-3, 12px) var(--ggui-spacing-4, 16px)"
                    style={{ maxWidth: '70%' }}
                  >
                    {!isCurrentUser && (
                      <Text
                        variant="label"
                        color="var(--ggui-color-onSurface, #18181b)"
                        size="sm"
                      >
                        {msg.sender || 'Unknown'}
                      </Text>
                    )}
                    <Text
                      variant="body"
                      color={
                        isCurrentUser
                          ? '#ffffff'
                          : 'var(--ggui-color-onSurface, #18181b)'
                      }
                    >
                      {msg.text || ''}
                    </Text>
                    <Text
                      variant="caption"
                      color={
                        isCurrentUser
                          ? 'rgba(255, 255, 255, 0.7)'
                          : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                      }
                      size="xs"
                      align="right"
                    >
                      {formatTime(msg.timestamp)}
                    </Text>
                  </Box>
                  {isCurrentUser && (
                    <Avatar name={props.currentUser} size="sm" shape="circle" />
                  )}
                </Stack>
              );
            })}
            <div ref={messagesEndRef} />
          </Box>

          <Divider margin="var(--ggui-spacing-2)" />

          {/* Input area */}
          <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="end">
            <TextArea
              label="Message"
              placeholder="Type your message... (Shift+Enter for newline)"
              value={messageText}
              onChange={setMessageText}
              rows={3}
            />
            <Button
              variant="primary"
              size="md"
              onClick={handleSendMessage}
              disabled={!messageText.trim()}
              style={{ flex: 0 }}
            >
              Send
            </Button>
           </Stack>
        </Card>
      </Container>
    );
  }

