// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State for merged stock data
  const [stocksData, setStocksData] = useState(props.stocks || []);

  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [highlightedSymbol, setHighlightedSymbol] = useState<string | null>(null);
  const [lastProcessedUpdateId, setLastProcessedUpdateId] = useState<string | null>(null);
  const [lastMarketStatus, setLastMarketStatus] = useState<string | null>(null);

  // Real-time clock update independent of price updates
  // Remove clock timer — use lastUpdated timestamp instead

  // Merge live price updates into stock data
  // Merge live price updates into stock data with deduplication
  useEffect(() => {
    if (priceUpdate.latest && priceUpdate.latest.symbol) {
      // Create unique ID for this update to prevent duplicates
      const updateId = `${priceUpdate.latest.symbol}:${priceUpdate.latest.price}:${priceUpdate.latest.change}:${priceUpdate.latest.changePercent}`;
      if (updateId === lastProcessedUpdateId) return; // Skip if already processed
      setLastProcessedUpdateId(updateId);

      setStocksData(prevStocks => {
        const stock = prevStocks.find(s => s.symbol === priceUpdate.latest?.symbol);
        if (!stock) return prevStocks; // Validate stock exists

        return prevStocks.map(s =>
          s.symbol === priceUpdate.latest?.symbol
            ? {
                ...s,
                price: priceUpdate.latest.price ?? s.price,
                change: priceUpdate.latest.change ?? s.change,
                changePercent: priceUpdate.latest.changePercent ?? s.changePercent,
              }
            : s
        );
      });
      setLastUpdated(new Date());
      setHighlightedSymbol(priceUpdate.latest.symbol);
      // Clear highlight after animation (300ms for smoother flash effect)
      const timer = setTimeout(() => setHighlightedSymbol(null), 300);
      return () => clearTimeout(timer);
    }
  }, [priceUpdate.latest, lastProcessedUpdateId]);

  // Format price with 2 decimals
  const formatPrice = (price?: number) => {
    if (price === undefined || price === null) return 'N/A';
    return `$${price.toFixed(2)}`;
  };

  // Determine color based on change
  const getChangeColor = (changePercent?: number) => {
    if (changePercent === undefined || changePercent === null) return 'var(--ggui-color-onSurfaceVariant)';
    return changePercent >= 0 ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
  };

  // Get border color based on change
  const getBorderColor = (changePercent?: number) => {
    if (changePercent === undefined || changePercent === null) return 'var(--ggui-color-outline)';
    return changePercent >= 0 ? 'var(--ggui-color-success-200)' : 'var(--ggui-color-error-200)';
  };

  // Get arrow icon
  const getArrowIcon = (changePercent?: number) => {
    if (changePercent === undefined || changePercent === null) return null;
    return changePercent >= 0 ? '▲' : '▼';
  };
  // Define pulse animation keyframes
  // Define flash animation keyframes with smooth fade effect
  const pulseKeyframes = `
    @keyframes ggui-pulse {
      0% { background-color: var(--ggui-color-primary-50, #f0f9ff); }
      100% { background-color: transparent; }
    }
    @media (max-width: 768px) {
      .stock-grid {
        grid-template-columns: 1fr;
      }
    }
  `;

  return (
    <>
      <style>{pulseKeyframes}</style>
      <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
       <Stack gap={32} direction="vertical">
        {/* Header */}
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={1} color="var(--ggui-color-onSurface)">
            Market Watch
          </Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Last Updated: {lastUpdated.toLocaleTimeString()}
          </Text>

        {/* Market Status */}
        {marketStatus.latest && marketStatus.latest.status !== lastMarketStatus && (
          <Box
            padding="var(--ggui-spacing-4)"
            background="var(--ggui-color-primary-50)"
            borderRadius={8}
          >
            <Text variant="body" color="var(--ggui-color-primary-700)">
              Market Status: <strong>{marketStatus.latest.status}</strong>
            </Text>
          </Box>
        )}
        {marketStatus.latest && setLastMarketStatus(marketStatus.latest.status || null)}

        {/* Stock Cards Grid - responsive layout */}
        <div
          className="stock-grid"
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(3, 1fr)',
            gap: 'var(--ggui-spacing-6)',
          }}
        >
          {stocksData && stocksData.length > 0 ? (
            stocksData.map((stock) => {
              const isHighlighted = stock.symbol === highlightedSymbol;
              const changeColor = getChangeColor(stock.changePercent);
              const borderColor = getBorderColor(stock.changePercent);
              const arrowIcon = getArrowIcon(stock.changePercent);

              return (
                <Card
                  key={stock.symbol}
                  shadow="md"
                  padding="var(--ggui-spacing-4)"
                  border={true}
                  radius="lg"
                    borderColor: borderColor,
                    borderWidth: '2px',
                    animation: isHighlighted ? 'ggui-pulse 300ms ease-out forwards' : 'none',
                    transition: 'all 200ms ease-in-out',
                  }}
                  <Stack gap={8} direction="vertical">
                    {/* Ticker Symbol */}
                    <Text
                      variant="overline"
                      size="2xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface)"
                    >
                      {stock.symbol || 'N/A'}
                    </Text>

                    {/* Company Name */}
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      {stock.name || 'Unknown'}
                    </Text>

                    <Divider margin={8} />

                    {/* Current Price */}
                     <Stack direction="vertical" gap={4}>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                        Price
                      </Text>
                      <Text
                        variant="bodyLarge"
                        weight="semibold"
                        color="var(--ggui-color-onSurface)"
                      >
                        {formatPrice(stock.price)}
                      </Text>
                    </Stack>

                    {/* Change Amount and Percentage */}
                     <Stack direction="horizontal" gap={8} align="center">
                       <Stack direction="vertical" gap={4} align="start">
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                          Change
                        </Text>
                        <Text variant="body" weight="medium" color={changeColor}>
                          {stock.change !== undefined && stock.change !== null
                            ? (stock.change >= 0 ? '+' : '') + stock.change.toFixed(2)
                            : 'N/A'}
                        </Text>
                      </Stack>

                       <Stack direction="vertical" gap={4} align="start">
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                          Percent
                        </Text>
                         <Stack direction="horizontal" gap={4} align="center">
                          <Text variant="body" weight="medium" color={changeColor}>
                            {stock.changePercent !== undefined && stock.changePercent !== null
                              ? (stock.changePercent >= 0 ? '+' : '') + stock.changePercent.toFixed(2) + '%'
                              : 'N/A'}
                          </Text>
                          {arrowIcon && (
                            <Text variant="body" weight="bold" color={changeColor}>
                              {arrowIcon}
                            </Text>
                          )}
                        </Stack>
                      </Stack>
                    </Stack>
                  </Stack>
                </Card>
              );
            })
           ) : (
             <Text color="var(--ggui-color-onSurfaceVariant)">
               {stocksData.length === 0 ? 'No stocks available' : 'Loading stocks...'}
             </Text>
           )}
        </div>
      </Stack>
      </Container>
    </>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };


export default function Component(props: Props) {
  // State management for the 3-step wizard
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || (props.avatarOptions.length > 0 ? props.avatarOptions[0] : ''),
    role: props.initialProfile.role || (props.roleOptions.length > 0 ? props.roleOptions[0] : ''),
    emailNotifications: props.initialProfile.emailNotifications !== false,
    theme: props.initialProfile.theme || 'light',
  });
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Validation helpers
  const isValidEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const validateStep = (step: number): boolean => {
    const newErrors: Record<string, string> = {};

    if (step === 1) {
      if (!formData.name.trim()) newErrors.name = 'Name is required';
      if (!formData.email.trim()) newErrors.email = 'Email is required';
      else if (!isValidEmail(formData.email)) newErrors.email = 'Invalid email format';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  // Navigation handlers
  const handleNext = useCallback(() => {
    if (validateStep(currentStep)) {
      setCurrentStep(currentStep + 1);
      setErrors({});
    }
  }, [currentStep, formData]);

  const handleBack = useCallback(() => {
    setCurrentStep(Math.max(1, currentStep - 1));
    setErrors({});
  }, [currentStep]);

  const complete = useAction<ActionCompletePayload>('onComplete');

  const handleComplete = useCallback(() => {
    if (validateStep(currentStep)) {
      complete(formData);
    }
  }, [formData, currentStep]);

  const handleFieldChange = useCallback((field: keyof typeof formData, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    setErrors(prev => ({ ...prev, [field]: '' }));
  }, []);

  // Progress calculation
  const progressPercentage = (currentStep / 3) * 100;
  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Step indicator and progress bar */}
        <Stack gap="var(--ggui-spacing-4)">
          <Stack direction="horizontal" justify="between" align="center">
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={2}>Account Setup</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Step {currentStep} of 3
              </Text>
            </Stack>
            <Badge variant="primary" size="lg">{currentStep}/3</Badge>
          </Stack>
          <Progress value={progressPercentage} max={100} size="md" variant="default" />
        </Stack>

        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-6)">
              <Stack gap="var(--ggui-spacing-2)">
                <Heading level={3}>Profile Setup</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Start by telling us about yourself
                </Text>
              </Stack>

              <Input
                label="Full Name"
                value={formData.name}
                onChange={(value) => handleFieldChange('name', value)}
                placeholder="John Doe"
                error={errors.name}
                required
              />

              <Input
                label="Email Address"
                type="email"
                value={formData.email}
                onChange={(value) => handleFieldChange('email', value)}
                placeholder="you@example.com"
                error={errors.email}
                required
              />

              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label">Avatar</Text>
                <Stack direction="horizontal" gap="var(--ggui-spacing-4)" wrap align="center">
                  {props.avatarOptions.map((emoji) => (
                    <Box
                      key={emoji}
                      as={Clickable}
                      onClick={() => handleFieldChange('avatar', emoji)}
                      paddingX="var(--ggui-spacing-2)"
                      paddingY="var(--ggui-spacing-2)"
                      borderRadius="var(--ggui-shape-radius-md, 8px)"
                      background={formData.avatar === emoji ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                      style={{ cursor: 'pointer', transition: 'all 200ms ease-in-out', border: formData.avatar === emoji ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '2px solid transparent' }}
                    >
                      <Text size="3xl">{emoji}</Text>
                    </Box>
                  ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-6)">
              <Stack gap="var(--ggui-spacing-2)">
                <Heading level={3}>Preferences</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Customize your experience
                </Text>
              </Stack>

              <Select
                label="Role"
                value={formData.role}
                onChange={(value) => handleFieldChange('role', value)}
                options={props.roleOptions.map(role => ({ value: role, label: role }))}
                placeholder="Select a role"
              />
              <Toggle
                label="Email Notifications"
                checked={formData.emailNotifications}
                onChange={(value) => handleFieldChange('emailNotifications', value)}
                size="md"
              />

              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label">Theme Preference</Text>
                <RadioGroup
                  label="Theme Preference"
                  value={formData.theme}
                  onChange={(value) => handleFieldChange('theme', value)}
                  options={[
                    { value: 'light', label: 'Light' },
                    { value: 'dark', label: 'Dark' },
                  ]}
                  direction="horizontal"
                />
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 3: Review & Confirm */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-6)">
              <Stack gap="var(--ggui-spacing-2)">
                <Heading level={3}>Review & Confirm</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Please review your information before completing
                </Text>
              </Stack>

              {/* Summary Cards */}
              <Card border shadow="none" padding="var(--ggui-spacing-4)" radius="md">
                <Stack gap="var(--ggui-spacing-4)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
                    <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                      <Avatar name={formData.name} size="sm" />
                      <Text>{formData.name}</Text>
                    </Stack>
                  </Stack>
                  <Divider margin="var(--ggui-spacing-2)" />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
                    <Text>{formData.email}</Text>
                  </Stack>
                  <Divider margin="var(--ggui-spacing-2)" />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Avatar</Text>
                    <Text size="2xl">{formData.avatar}</Text>
                  </Stack>
                  <Divider margin="var(--ggui-spacing-2)" />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role</Text>
                    <Badge variant="primary">{formData.role}</Badge>
                  </Stack>
                  <Divider margin="var(--ggui-spacing-2)" />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email Notifications</Text>
                    <Badge variant={formData.emailNotifications ? 'success' : 'secondary'}>
                      {formData.emailNotifications ? 'Enabled' : 'Disabled'}
                    </Badge>
                  </Stack>
                  <Divider margin="var(--ggui-spacing-2)" />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text>
                    <Badge variant="primary">{formData.theme.charAt(0).toUpperCase() + formData.theme.slice(1)}</Badge>
                  </Stack>
                </Stack>
              </Card>
            </Stack>
          </Card>
        )}

        {/* Navigation buttons */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="between" align="center">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          <Spacer size="flex" />
          {currentStep < 3 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={!validateStep(currentStep)}
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleComplete}
            >
              Complete Setup
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}
